import React, { useState, useEffect } from 'react';

export default function App() {
  const [count, setCount] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function init() {
      const saved = await window.forge.db.get('counter_app', 'global_count');
      if (saved?.value !== undefined) {
        setCount(saved.value);
      }
      setLoading(false);
    }
    init();
  }, []);

  const updateCount = async (newVal) => {
    setCount(newVal);
    await window.forge.db.set('counter_app', 'global_count', { value: newVal });
  };

  if (loading) return <div className="min-h-screen bg-neutral-950 flex items-center justify-center text-neutral-400">Initializing...</div>;

  return (
    <div className="min-h-screen bg-neutral-950 text-neutral-100 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-sm bg-neutral-900 border border-neutral-800 rounded-3xl p-8 shadow-2xl shadow-black/50 backdrop-blur-md">
        <div className="text-center mb-8">
          <div className="text-neutral-400 text-sm font-medium uppercase tracking-widest mb-4">
            Current Count
          </div>
          <div className="text-8xl font-light font-mono text-white tracking-tighter">
            {count}
          </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={() => updateCount(count - 1)}
            className="flex-1 py-4 bg-neutral-800 hover:bg-neutral-700 active:bg-neutral-600 rounded-2xl text-xl font-bold transition-all duration-200 border border-neutral-700"
          >
            -
          </button>
          <button 
            onClick={() => updateCount(count + 1)}
            className="flex-1 py-4 bg-blue-600 hover:bg-blue-500 active:bg-blue-700 rounded-2xl text-xl font-bold transition-all duration-200"
          >
            +
          </button>
        </div>

        <button 
          onClick={() => updateCount(0)}
          className="w-full mt-4 py-2 text-neutral-500 hover:text-neutral-300 text-sm font-medium transition-colors"
        >
          Reset Counter
        </button>
      </div>

      <footer className="text-center p-4 text-neutral-400 text-xs opacity-80 flex justify-center items-center gap-1.5 mt-auto">
        <span>Built with</span> 
        <img src="https://forge-app.vercel.app/logo.png" alt="Forge" className="w-3.5 h-3.5 rounded-sm object-cover" /> 
        <a href="https://forge-app.vercel.app" className="text-blue-500 font-semibold tracking-wide no-underline">FORGE</a>
      </footer>
    </div>
  );
}
